<!DOCTYPE html><html lang="ko"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width"><title>Webtoon</title><link rel="icon" href="static/favicon.svg"><link rel="stylesheet" href="static/common.css"></head><body><?php foreach ($titles as $title): ?><div class="title"><a class="thumbnail" href="list.php?titleId=<?= $title["id"] ?>"><img src="<?= $title["thumbnail"] ?>"></a><a class="name" href="list.php?titleId=<?= $title["id"] ?>"><?= html_esc($title["name"]) ?></a><div class="artists"><?php foreach ($artists[$title["id"]] as $artist): ?><div class="artist"><a class="name"<?php if ($artist["profile"] !== null): ?> href="<?= $artist["profile"] ?>" target="_blank" rel="noopener noreferrer"<?php endif; ?>><?= html_esc($artist["name"]) ?></a><div class="role"><?= $artist["role"] ?></div></div><?php endforeach; ?></div></div><?php endforeach; ?><div class="navigator"><a class="button"<?php if ($page > 1): ?> href="index.php?page=<?= $page - 1 ?>"<?php endif; ?>>&#xf044;</a><?= $page ?> / <?= $page_max ?><a class="button"<?php if ($page < $page_max): ?> href="index.php?page=<?= $page + 1 ?>"<?php endif; ?>>&#xf045;</a></div></body></html>